+const minmaxPattern = /^minmax\\(\\s*(\\d+(?:\\.\\d+)?)\\s*,\\s*(\\d+(?:\\.\\d+)?|\\d*(?:\\.\\d+)?fr)\\s*\\)$/;
+const fractionPattern = /^(\\d*(?:\\.\\d+)?)fr$/;
